func playgroundAlpineData(agents []*agent.Config, personas []*persona.Persona, skills []*skill.Skill, traits []*trait.Trait, behaviors []*behavior.Behavior, cfg cortex.Config, selectedAgent string) string {
	// Build agent config lookup map for client-side agent loading.
	type agentJS struct {
		Name          string   `json:"name"`
		Model         string   `json:"model"`
		Temperature   float64  `json:"temperature"`
		MaxSteps      int      `json:"max_steps"`
		MaxTokens     int      `json:"max_tokens"`
		ReasoningLoop string   `json:"reasoning_loop"`
		PersonaRef    string   `json:"persona_ref"`
		Skills        []string `json:"skills"`
		Traits        []string `json:"traits"`
		Behaviors     []string `json:"behaviors"`
	}

	agentMap := make(map[string]agentJS, len(agents))
	for _, a := range agents {
		agentMap[a.Name] = agentJS{
			Name:          a.Name,
			Model:         a.Model,
			Temperature:   a.Temperature,
			MaxSteps:      a.MaxSteps,
			MaxTokens:     a.MaxTokens,
			ReasoningLoop: a.ReasoningLoop,
			PersonaRef:    a.PersonaRef,
			Skills:        a.InlineSkills,
			Traits:        a.InlineTraits,
			Behaviors:     a.InlineBehaviors,
		}
	}
	agentMapJSON, _ := json.Marshal(agentMap)

	return fmt.Sprintf(`{
		agentName: %q,
		agentConfigs: %s,
		activeTab: 'chat',
		sidebarCollapsed: false,
		useCustomConfig: false,

		messages: [],
		inputText: '',
		isStreaming: false,
		isThinking: false,
		currentRunId: null,
		error: '',
		abortController: null,

		overrides: {
			model: %q,
			temperature: %s,
			max_steps: %d,
			max_tokens: %d,
			reasoning_loop: %q,
			persona_ref: '',
		},

		selectedSkills: [],
		selectedTraits: [],
		selectedBehaviors: [],

		runs: [],

		compare: {
			syncInput: false,
			panelA: {
				agentName: '',
				messages: [],
				inputText: '',
				isStreaming: false,
				isThinking: false,
				abortController: null,
				lastDuration: null,
				lastTokens: null,
			},
			panelB: {
				agentName: '',
				messages: [],
				inputText: '',
				isStreaming: false,
				isThinking: false,
				abortController: null,
				lastDuration: null,
				lastTokens: null,
			},
		},

		loadAgentConfig(name) {
			this.agentName = name;
			this.messages = [];
			this.currentRunId = null;
			this.error = '';
			if (name && this.agentConfigs[name]) {
				const ac = this.agentConfigs[name];
				this.overrides.model = ac.model || %q;
				this.overrides.temperature = ac.temperature || %s;
				this.overrides.max_steps = ac.max_steps || %d;
				this.overrides.max_tokens = ac.max_tokens || %d;
				this.overrides.reasoning_loop = ac.reasoning_loop || %q;
				this.overrides.persona_ref = ac.persona_ref || '';
				this.selectedSkills = ac.skills || [];
				this.selectedTraits = ac.traits || [];
				this.selectedBehaviors = ac.behaviors || [];
			}
			this.refreshPromptPreview();
		},

		async sendMessage() {
			if (!this.inputText.trim() || this.isStreaming || !this.agentName) return;
			const userMsg = this.inputText.trim();
			this.inputText = '';
			this.error = '';
			const now = new Date().toLocaleTimeString('en-US', {hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit'});
			this.messages.push({role: 'user', content: userMsg, timestamp: now});
			this.scrollToBottom();
			this.isStreaming = true;
			this.isThinking = true;
			const startTime = Date.now();

			const body = {input: userMsg};
			if (this.useCustomConfig) {
				body.overrides = {
					model: this.overrides.model,
					temperature: this.overrides.temperature,
					max_steps: this.overrides.max_steps,
					max_tokens: this.overrides.max_tokens,
					reasoning_loop: this.overrides.reasoning_loop,
					persona_ref: this.overrides.persona_ref,
					inline_skills: this.selectedSkills,
					inline_traits: this.selectedTraits,
					inline_behaviors: this.selectedBehaviors,
				};
			}

			try {
				this.abortController = new AbortController();
				const resp = await fetch('/cortex/agents/' + encodeURIComponent(this.agentName) + '/stream', {
					method: 'POST',
					headers: {'Content-Type': 'application/json'},
					body: JSON.stringify(body),
					signal: this.abortController.signal
				});

				if (!resp.ok) {
					const err = await resp.json().catch(() => ({}));
					throw new Error(err.error || err.message || 'Request failed: ' + resp.status);
				}

				const reader = resp.body.getReader();
				const decoder = new TextDecoder();
				let buffer = '';
				let assistantMsg = null;
				let currentEvent = '';
				let output = '';
				let stepCount = 0;

				while (true) {
					const {done, value} = await reader.read();
					if (done) break;
					buffer += decoder.decode(value, {stream: true});

					const lines = buffer.split('\n');
					buffer = lines.pop();

					for (const line of lines) {
						if (line.startsWith('event: ')) {
							currentEvent = line.slice(7).trim();
							continue;
						}
						if (line.startsWith('data: ')) {
							const data = JSON.parse(line.slice(6));
							switch (currentEvent) {
								case 'run_started':
									this.currentRunId = data.run_id;
									break;
								case 'step':
									stepCount++;
									break;
								case 'token':
									if (this.isThinking) {
										this.isThinking = false;
										const ts = new Date().toLocaleTimeString('en-US', {hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit'});
										assistantMsg = {role: 'assistant', content: '', timestamp: ts};
										this.messages.push(assistantMsg);
									}
									if (assistantMsg) {
										assistantMsg.content += data.content || '';
										output = assistantMsg.content;
									}
									break;
								case 'tool_call':
									this.messages.push({role: 'tool_call', tool_name: data.tool_name, content: data.arguments || '', _expanded: false});
									break;
								case 'checkpoint':
									this.messages.push({role: 'checkpoint', content: data.reason, checkpoint_id: data.checkpoint_id, _resolved: false, _decision: ''});
									break;
								case 'done':
									break;
								case 'error':
									this.error = data.message || 'Unknown error';
									break;
							}
							this.scrollToBottom();
						}
					}
				}

				// Record run in history.
				const elapsed = Date.now() - startTime;
				this.runs.unshift({
					run_id: this.currentRunId || 'unknown',
					agent_name: this.agentName,
					state: this.error ? 'failed' : 'completed',
					input: userMsg,
					output: output,
					step_count: stepCount,
					duration_ms: elapsed,
					timestamp: now,
					overrides_used: this.useCustomConfig,
					overrides: this.useCustomConfig ? {...this.overrides} : null,
					_expanded: false,
				});
			} catch(e) {
				if (e.name !== 'AbortError') {
					this.error = e.message;
					if (this.isThinking) {
						this.isThinking = false;
					}
				}
			}
			this.isStreaming = false;
			this.isThinking = false;
			this.abortController = null;
		},

		async cancelRun() {
			if (this.abortController) {
				this.abortController.abort();
			}
			if (this.currentRunId) {
				await fetch('/cortex/runs/' + this.currentRunId + '/cancel', {method: 'POST'}).catch(() => {});
			}
			this.isStreaming = false;
			this.isThinking = false;
		},

		async clearChat() {
			if (this.agentName) {
				await fetch('/cortex/agents/' + encodeURIComponent(this.agentName) + '/memory', {method: 'DELETE'}).catch(() => {});
			}
			this.messages = [];
			this.currentRunId = null;
			this.error = '';
		},

		async resolveCheckpoint(cpId, approved) {
			try {
				await fetch('/cortex/checkpoints/' + cpId + '/resolve', {
					method: 'POST',
					headers: {'Content-Type': 'application/json'},
					body: JSON.stringify({decision: approved ? 'approved' : 'rejected', decided_by: 'playground'})
				});
				for (const msg of this.messages) {
					if (msg.checkpoint_id === cpId) {
						msg._resolved = true;
						msg._decision = approved ? 'Approved' : 'Rejected';
					}
				}
			} catch(e) {
				this.error = 'Failed to resolve checkpoint: ' + e.message;
			}
		},

		refreshPromptPreview() {
			const params = new URLSearchParams();
			if (this.agentName) params.set('agent', this.agentName);
			if (this.overrides.persona_ref) params.set('persona', this.overrides.persona_ref);
			if (this.selectedSkills.length) params.set('skills', this.selectedSkills.join(','));
			if (this.selectedTraits.length) params.set('traits', this.selectedTraits.join(','));
			const container = document.getElementById('prompt-preview-container');
			if (container) {
				container.setAttribute('hx-get', '/playground/preview-prompt?' + params.toString());
				htmx.trigger(container, 'htmx:trigger');
				htmx.ajax('GET', '/playground/preview-prompt?' + params.toString(), {target: '#prompt-preview-content', swap: 'outerHTML'});
			}
		},

		// --- Compare Panel Methods ---

		onCompareAgentChange(panel) {
			const p = panel === 'A' ? this.compare.panelA : this.compare.panelB;
			p.messages = [];
			p.lastDuration = null;
			p.lastTokens = null;
		},

		async sendCompareMessage(panel) {
			const p = panel === 'A' ? this.compare.panelA : this.compare.panelB;
			if (!p.inputText.trim() || p.isStreaming || !p.agentName) return;
			const userMsg = p.inputText.trim();
			p.inputText = '';

			// If sync is on, send to both panels.
			if (this.compare.syncInput) {
				const other = panel === 'A' ? this.compare.panelB : this.compare.panelA;
				if (other.agentName && !other.isStreaming) {
					other.inputText = '';
					this._streamToPanel(other, userMsg);
				}
			}

			await this._streamToPanel(p, userMsg);
		},

		async _streamToPanel(p, userMsg) {
			p.messages.push({role: 'user', content: userMsg});
			p.isStreaming = true;
			p.isThinking = true;
			const startTime = Date.now();

			try {
				p.abortController = new AbortController();
				const resp = await fetch('/cortex/agents/' + encodeURIComponent(p.agentName) + '/stream', {
					method: 'POST',
					headers: {'Content-Type': 'application/json'},
					body: JSON.stringify({input: userMsg}),
					signal: p.abortController.signal
				});

				if (!resp.ok) {
					const err = await resp.json().catch(() => ({}));
					throw new Error(err.error || 'Request failed: ' + resp.status);
				}

				const reader = resp.body.getReader();
				const decoder = new TextDecoder();
				let buffer = '';
				let assistantMsg = null;
				let currentEvent = '';

				while (true) {
					const {done, value} = await reader.read();
					if (done) break;
					buffer += decoder.decode(value, {stream: true});

					const lines = buffer.split('\n');
					buffer = lines.pop();

					for (const line of lines) {
						if (line.startsWith('event: ')) {
							currentEvent = line.slice(7).trim();
							continue;
						}
						if (line.startsWith('data: ')) {
							const data = JSON.parse(line.slice(6));
							switch (currentEvent) {
								case 'token':
									if (p.isThinking) {
										p.isThinking = false;
										assistantMsg = {role: 'assistant', content: ''};
										p.messages.push(assistantMsg);
									}
									if (assistantMsg) {
										assistantMsg.content += data.content || '';
									}
									break;
								case 'done':
									break;
								case 'error':
									this.error = data.message || 'Unknown error';
									break;
							}
						}
					}
				}

				const elapsed = Date.now() - startTime;
				p.lastDuration = elapsed;
				p.lastTokens = assistantMsg ? assistantMsg.content.length : 0;
			} catch(e) {
				if (e.name !== 'AbortError') {
					this.error = e.message;
				}
			}
			p.isStreaming = false;
			p.isThinking = false;
			p.abortController = null;
		},

		clearBothPanels() {
			this.compare.panelA.messages = [];
			this.compare.panelA.lastDuration = null;
			this.compare.panelA.lastTokens = null;
			this.compare.panelB.messages = [];
			this.compare.panelB.lastDuration = null;
			this.compare.panelB.lastTokens = null;
		},

		scrollToBottom() {
			this.$nextTick(() => {
				const el = this.$refs.messageContainer;
				if (el) el.scrollTop = el.scrollHeight;
			});
		}
	}`,
		selectedAgent,
		string(agentMapJSON),
		cfg.DefaultModel,
		strconv.FormatFloat(cfg.DefaultTemperature, 'f', 1, 64),
		cfg.DefaultMaxSteps,
		cfg.DefaultMaxTokens,
		cfg.DefaultReasoningLoop,
		// loadAgentConfig defaults
		cfg.DefaultModel,
		strconv.FormatFloat(cfg.DefaultTemperature, 'f', 1, 64),
		cfg.DefaultMaxSteps,
		cfg.DefaultMaxTokens,
		cfg.DefaultReasoningLoop,
	)
}

